package com.hospital.management.dao.impl;import com.hospital.management.dao.MedicalRecordDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.time.*;import java.util.ArrayList;import java.util.List;import java.util.Optional;
/** Oracle JDBC medical-record persistence with bound search/filter values. */
public class MedicalRecordDaoImpl implements MedicalRecordDao {private static final String SELECT="SELECT m.*,a.APPOINTMENT_DATE,a.START_TIME,p.PATIENT_NUMBER,p.FIRST_NAME||' '||p.LAST_NAME PATIENT_NAME,d.FIRST_NAME||' '||d.LAST_NAME DOCTOR_NAME,d.DEPARTMENT_ID,dep.DEPARTMENT_NAME FROM MEDICAL_RECORDS m JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=m.APPOINTMENT_ID JOIN PATIENTS p ON p.PATIENT_ID=m.PATIENT_ID JOIN DOCTORS d ON d.DOCTOR_ID=m.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ";
public Optional<MedicalRecord> findById(Long id)throws SQLException{return one("m.MEDICAL_RECORD_ID",id);}public Optional<MedicalRecord> findByAppointmentId(Long id)throws SQLException{return one("m.APPOINTMENT_ID",id);}private Optional<MedicalRecord>one(String field,Long id)throws SQLException{if(id==null)return Optional.empty();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(SELECT+"WHERE "+field+"=?")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}
public Page<MedicalRecord>findAll(PageRequest p,Long pi,Long di,Long dep,LocalDate from,LocalDate to)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(SELECT+where()+" ORDER BY m.VISIT_DATE DESC,m.MEDICAL_RECORD_ID DESC OFFSET ? ROWS FETCH NEXT ? ROWS ONLY")){int i=bind(s,p.getSearchTerm(),pi,di,dep,from,to);s.setInt(i++,p.getOffset());s.setInt(i,p.getPageSize());List<MedicalRecord>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return new Page<>(x,p.getPageNumber(),p.getPageSize(),count(p.getSearchTerm(),pi,di,dep,from,to));}}
public long count(String q,Long pi,Long di,Long dep,LocalDate from,LocalDate to)throws SQLException{String joins="FROM MEDICAL_RECORDS m JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=m.APPOINTMENT_ID JOIN PATIENTS p ON p.PATIENT_ID=m.PATIENT_ID JOIN DOCTORS d ON d.DOCTOR_ID=m.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT COUNT(1) "+joins+where())){bind(s,q,pi,di,dep,from,to);try(ResultSet r=s.executeQuery()){r.next();return r.getLong(1);}}}
private String where(){return"WHERE (? IS NULL OR UPPER(p.PATIENT_NUMBER||' '||p.FIRST_NAME||' '||p.LAST_NAME||' '||d.FIRST_NAME||' '||d.LAST_NAME||' '||dep.DEPARTMENT_NAME||' '||m.SYMPTOMS||' '||m.DIAGNOSIS||' '||m.ALLERGIES) LIKE ? ESCAPE '\\') AND (? IS NULL OR m.PATIENT_ID=?) AND (? IS NULL OR m.DOCTOR_ID=?) AND (? IS NULL OR d.DEPARTMENT_ID=?) AND (? IS NULL OR m.VISIT_DATE>=?) AND (? IS NULL OR m.VISIT_DATE<?) ";}private int bind(PreparedStatement s,String q,Long pi,Long di,Long dep,LocalDate from,LocalDate to)throws SQLException{String t=q==null||q.isBlank()?null:"%"+q.trim().toUpperCase().replace("\\","\\\\").replace("%","\\%").replace("_","\\_")+"%";int i=1;s.setString(i++,t);s.setString(i++,t);i=pair(s,i,pi);i=pair(s,i,di);i=pair(s,i,dep);i=date(s,i,from);return date(s,i,to==null?null:to.plusDays(1));}private int pair(PreparedStatement s,int i,Long v)throws SQLException{if(v==null){s.setNull(i++,Types.NUMERIC);s.setNull(i++,Types.NUMERIC);}else{s.setLong(i++,v);s.setLong(i++,v);}return i;}private int date(PreparedStatement s,int i,LocalDate v)throws SQLException{if(v==null){s.setNull(i++,Types.TIMESTAMP);s.setNull(i++,Types.TIMESTAMP);}else{s.setTimestamp(i++,Timestamp.valueOf(v.atStartOfDay()));s.setTimestamp(i++,Timestamp.valueOf(v.atStartOfDay()));}return i;}
public long create(Connection c,MedicalRecord r)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO MEDICAL_RECORDS(PATIENT_ID,DOCTOR_ID,APPOINTMENT_ID,VISIT_DATE,SYMPTOMS,DIAGNOSIS,TREATMENT_NOTES,ALLERGIES,BLOOD_PRESSURE,TEMPERATURE,WEIGHT,HEIGHT) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)",new String[]{"MEDICAL_RECORD_ID"})){bindWrite(s,r,false);s.executeUpdate();try(ResultSet k=s.getGeneratedKeys()){if(k.next())return k.getLong(1);}throw new SQLException("No medical record identifier returned");}}
public boolean update(Connection c,MedicalRecord r)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE MEDICAL_RECORDS SET SYMPTOMS=?,DIAGNOSIS=?,TREATMENT_NOTES=?,ALLERGIES=?,BLOOD_PRESSURE=?,TEMPERATURE=?,WEIGHT=?,HEIGHT=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE MEDICAL_RECORD_ID=?")){s.setString(1,r.getSymptoms());s.setString(2,r.getDiagnosis());s.setString(3,r.getTreatmentNotes());s.setString(4,r.getAllergies());s.setString(5,r.getBloodPressure());s.setBigDecimal(6,r.getTemperature());s.setBigDecimal(7,r.getWeight());s.setBigDecimal(8,r.getHeight());s.setLong(9,r.getMedicalRecordId());return s.executeUpdate()==1;}}
private void bindWrite(PreparedStatement s,MedicalRecord r,boolean ignored)throws SQLException{s.setLong(1,r.getPatientId());s.setLong(2,r.getDoctorId());s.setLong(3,r.getAppointmentId());s.setTimestamp(4,Timestamp.valueOf(r.getVisitDate()));s.setString(5,r.getSymptoms());s.setString(6,r.getDiagnosis());s.setString(7,r.getTreatmentNotes());s.setString(8,r.getAllergies());s.setString(9,r.getBloodPressure());s.setBigDecimal(10,r.getTemperature());s.setBigDecimal(11,r.getWeight());s.setBigDecimal(12,r.getHeight());}
public boolean existsByAppointmentId(Long id)throws SQLException{return exists(id,null);}public boolean existsByAppointmentIdExcludingRecord(Long a,Long r)throws SQLException{return exists(a,r);}private boolean exists(Long a,Long r)throws SQLException{if(a==null)return false;String sql="SELECT 1 FROM MEDICAL_RECORDS WHERE APPOINTMENT_ID=?"+(r==null?"":" AND MEDICAL_RECORD_ID<>?")+" FETCH FIRST 1 ROW ONLY";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(sql)){s.setLong(1,a);if(r!=null)s.setLong(2,r);try(ResultSet x=s.executeQuery()){return x.next();}}}
private MedicalRecord map(ResultSet r)throws SQLException{MedicalRecord m=new MedicalRecord();m.setMedicalRecordId(r.getLong("MEDICAL_RECORD_ID"));m.setPatientId(r.getLong("PATIENT_ID"));m.setPatientNumber(r.getString("PATIENT_NUMBER"));m.setPatientName(r.getString("PATIENT_NAME"));m.setDoctorId(r.getLong("DOCTOR_ID"));m.setDoctorName(r.getString("DOCTOR_NAME"));m.setDepartmentId(r.getLong("DEPARTMENT_ID"));m.setDepartmentName(r.getString("DEPARTMENT_NAME"));long aid=r.getLong("APPOINTMENT_ID");m.setAppointmentId(r.wasNull()?null:aid);Date ad=r.getDate("APPOINTMENT_DATE");m.setAppointmentDate(ad==null?null:ad.toLocalDate());String st=r.getString("START_TIME");m.setAppointmentStartTime(st==null?null:LocalTime.parse(st));m.setSymptoms(r.getString("SYMPTOMS"));m.setDiagnosis(r.getString("DIAGNOSIS"));m.setTreatmentNotes(r.getString("TREATMENT_NOTES"));m.setAllergies(r.getString("ALLERGIES"));m.setBloodPressure(r.getString("BLOOD_PRESSURE"));m.setTemperature(r.getBigDecimal("TEMPERATURE"));m.setWeight(r.getBigDecimal("WEIGHT"));m.setHeight(r.getBigDecimal("HEIGHT"));Timestamp v=r.getTimestamp("VISIT_DATE"),c=r.getTimestamp("CREATED_AT"),u=r.getTimestamp("UPDATED_AT");m.setVisitDate(v==null?null:v.toLocalDateTime());m.setCreatedAt(c==null?null:c.toLocalDateTime());m.setUpdatedAt(u==null?null:u.toLocalDateTime());return m;}}
